{
  "functions": [
    {
      "name": "智能文本生成",
      "description": "根据用户输入的关键词或主题，自动生成高质量的文本内容，支持多种文体和格式。"
    },
    {
      "name": "写作建议",
      "description": "提供实时的写作建议和修改意见，帮助用户优化文本结构和语言表达。"
    }
  ],
  "roles": [
    {
      "name": "学生",
      "description": "帮助学生快速完成论文、作业等学术写作任务，提高写作效率和质量。"
    },
    {
      "name": "教育人士",
      "description": "辅助教师生成教学材料、教案和学术论文，减轻写作负担。"
    }
  ],
  "features": [
    {
      "name": "多场景适用",
      "description": "支持论文、公文、小说等多种写作场景，满足不同用户的写作需求。"
    }
  ],
  "scenarios": [
    {
      "name": "学术论文写作",
      "description": "用户输入论文主题和关键词，系统自动生成论文大纲和部分内容，帮助用户快速完成学术写作。"
    },
    {
      "name": "公文写作",
      "description": "根据用户提供的公文类型和内容要求，生成符合规范的公文文本，提高办公效率。"
    }
  ],
  "pricing_plan": [
    {
      "name": "免费试用",
      "description": "提供基础功能试用，适合新用户体验工具的基本功能。"
    },
    {
      "name": "高级会员",
      "description": "解锁全部功能，包括高级文本生成和个性化写作建议，适合高频用户。"
    }
  ],
  "usage": [
    {
      "name": "网页版使用",
      "description": "用户可以直接访问SongGuoAI官网，注册账号后即可开始使用。在输入框中输入写作主题或关键词，系统会自动生成相关内容。用户可以根据需要调整和修改生成的内容。"
    },
    {
      "name": "API集成",
      "description": "开发者可以通过API将SongGuoAI的文本生成功能集成到自己的应用中。具体集成方法可以参考官方文档，提供详细的API调用示例和参数说明。"
    }
  ]
}
